document.addEventListener("DOMContentLoaded", () => {
    let currentLang = localStorage.getItem("dga_lang") || "ru";
    const originalTexts = new WeakMap();

    // Map flag icon icons to UI quickly
    const flagMapping = {
        "ru": "twemoji:flag-russia",
        "uk": "twemoji:flag-ukraine",
        "pl": "twemoji:flag-poland",
        "en": "twemoji:flag-united-kingdom"
    };

    function translateNode(node) {
        if (node.nodeType === Node.TEXT_NODE) {
            let text = node.nodeValue;
            if (!text) return;
            if (!originalTexts.has(node)) {
                if (text.trim() === '') return;
                originalTexts.set(node, text);
            }
            let orig = originalTexts.get(node);
            let trimmed = orig.trim();
            let lookupKey = trimmed.replace(/\s+/g, ' ');
            if (lookupKey && dictionary[currentLang] && dictionary[currentLang][lookupKey]) {
                node.nodeValue = orig.replace(trimmed, dictionary[currentLang][lookupKey]);
            } else if (currentLang === "ru") {
                node.nodeValue = orig;
            }
        } else if (node.nodeType === Node.ELEMENT_NODE) {
            // skip script and style
            if (["SCRIPT", "STYLE", "ICONIFY-ICON"].includes(node.nodeName)) return;

            // walk children
            Array.from(node.childNodes).forEach(translateNode);

            // Translate placeholder if input
            if (node.placeholder) {
                if (!originalTexts.has(node)) originalTexts.set(node, node.placeholder);
                let orig = originalTexts.get(node);
                let trimmed = orig.trim();
                let lookupKey = trimmed.replace(/\s+/g, ' ');
                if (lookupKey && dictionary[currentLang] && dictionary[currentLang][lookupKey]) {
                    node.placeholder = orig.replace(trimmed, dictionary[currentLang][lookupKey]);
                } else if (currentLang === "ru") {
                    node.placeholder = orig;
                }
            }
        }
    }

    function applyLanguage(lang) {
        currentLang = lang;
        localStorage.setItem("dga_lang", lang);
        translateNode(document.body);

        // Update switcher UI
        const btn = document.querySelector('.lang-switcher__btn');
        if (btn) {
            const icon = btn.querySelector('iconify-icon');
            const text = btn.querySelector('span');
            if (icon) icon.setAttribute('icon', flagMapping[lang] || 'twemoji:flag-russia');
            if (text) text.textContent = lang.toUpperCase();
        }

        document.querySelectorAll('.lang-switcher__item').forEach(el => {
            el.classList.remove('active');
            if (el.dataset.lang === lang) el.classList.add('active');
        });
    }

    applyLanguage(currentLang);

    // Bind events
    document.querySelectorAll('.lang-switcher__item').forEach(item => {
        item.addEventListener('click', (e) => {
            e.preventDefault();
            const langToSet = item.dataset.lang;
            if (langToSet) applyLanguage(langToSet);
        });
    });
});
